/**
 * Vision Router Extension
 *
 * Routes commands/tool calls through a configurable vision model.
 * The vision provider and model are configurable via settings.
 *
 * Config files (merged, project takes precedence):
 * - ~/.pi/agent/vision-router.json (global)
 * - <cwd>/.pi/vision-router.json (project-local)
 *
 * Usage:
 *   /vision "describe this architecture" — routes to vision model
 *   /vision-config — opens settings UI
 *   LLM can call vision_query tool to route sub-tasks
 */

import { existsSync, readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { complete, type Message, type Model, type Api } from "@earendil-works/pi-ai";
import type { ExtensionAPI, ExtensionContext, Theme } from "@earendil-works/pi-coding-agent";
import { getAgentDir, getSettingsListTheme } from "@earendil-works/pi-coding-agent";
import { Container, type SettingItem, SettingsList, Text } from "@earendil-works/pi-tui";
import { Type } from "typebox";

// ============================================================
// Types
// ============================================================

interface VisionRouterConfig {
  provider: string;
  model: string;
  label?: string;
  baseUrl?: string;
  api?: string;
  apiKey?: string;
  instructions?: string;
  contextWindow?: number;
  maxTokens?: number;
  costInput?: number;
  costOutput?: number;
  costCacheRead?: number;
  costCacheWrite?: number;
}

interface VisionRouterState {
  config: VisionRouterConfig;
}

const DEFAULT_CONFIG: VisionRouterConfig = {
  provider: "kimi",
  model: "kimi-k2.6-2",
  label: "Kimi K2.6 Vision",
  baseUrl: "http://localhost:19530/v1",
  api: "openai-responses",
  apiKey: "",
  instructions: "You are a vision-specialist model. Analyze images and answer questions about them with detailed descriptions.",
  contextWindow: 128000,
  maxTokens: 8192,
  costInput: 0.6,
  costOutput: 3.0,
  costCacheRead: 0.3,
  costCacheWrite: 0.9,
};

// ============================================================
// Config Management
// ============================================================

function loadConfig(cwd: string): VisionRouterConfig {
  const globalPath = join(getAgentDir(), "vision-router.json");
  const projectPath = join(cwd, ".pi", "vision-router.json");

  let config = { ...DEFAULT_CONFIG };

  if (existsSync(globalPath)) {
    try {
      const globalConfig = JSON.parse(readFileSync(globalPath, "utf-8"));
      config = { ...config, ...globalConfig };
    } catch (err) {
      console.error(`Failed to load global vision-router config: ${err}`);
    }
  }

  if (existsSync(projectPath)) {
    try {
      const projectConfig = JSON.parse(readFileSync(projectPath, "utf-8"));
      config = { ...config, ...projectConfig };
    } catch (err) {
      console.error(`Failed to load project vision-router config: ${err}`);
    }
  }

  return config;
}

function saveConfig(config: VisionRouterConfig, cwd: string): void {
  const projectDir = join(cwd, ".pi");
  if (!existsSync(projectDir)) {
    writeFileSync(projectDir, "", { flag: "a" }); // noop just to check
  }
  const projectPath = join(projectDir, "vision-router.json");
  writeFileSync(projectPath, JSON.stringify(config, null, 2));
}

// ============================================================
// Extension
// ============================================================

export default function (pi: ExtensionAPI) {
  let config: VisionRouterConfig = { ...DEFAULT_CONFIG };
  let visionModel: Model<Api> | null = null;
  let registeredProvider = false;

  // Register the vision provider if not already available
  function registerVisionProvider() {
    if (registeredProvider) return;

    try {
      pi.registerProvider(config.provider, {
        baseUrl: config.baseUrl || DEFAULT_CONFIG.baseUrl!,
        apiKey: config.apiKey || undefined,
        api: (config.api || "openai-responses") as Api,
        models: [{
          id: config.model,
          name: config.label || `${config.provider}/${config.model}`,
          reasoning: false,
          input: ["text", "image"],
          cost: {
            input: config.costInput ?? DEFAULT_CONFIG.costInput!,
            output: config.costOutput ?? DEFAULT_CONFIG.costOutput!,
            cacheRead: config.costCacheRead ?? DEFAULT_CONFIG.costCacheRead!,
            cacheWrite: config.costCacheWrite ?? DEFAULT_CONFIG.costCacheWrite!,
          },
          contextWindow: config.contextWindow ?? DEFAULT_CONFIG.contextWindow!,
          maxTokens: config.maxTokens ?? DEFAULT_CONFIG.maxTokens!,
        }],
      });
      registeredProvider = true;
    } catch (err) {
      // Provider may already be registered
      console.error(`Failed to register vision provider: ${err}`);
    }
  }

  // Find the vision model in the registry
  function resolveVisionModel(ctx: ExtensionContext): Model<Api> | null {
    if (visionModel) return visionModel;

    const model = ctx.modelRegistry.find(config.provider, config.model);
    if (model) {
      visionModel = model;
      return model;
    }
    return null;
  }

  // Route a query through the vision model
  async function routeToVisionModel(
    query: string,
    imageUrls: string[],
    ctx: ExtensionContext,
    signal?: AbortSignal,
  ): Promise<string> {
    const model = resolveVisionModel(ctx);
    if (!model) {
      throw new Error(`Vision model ${config.provider}/${config.model} not found. Check your vision-router.json config.`);
    }

    const auth = await ctx.modelRegistry.getApiKeyAndHeaders(model);
    if (!auth.ok || !auth.apiKey) {
      throw new Error(auth.ok ? `No API key for ${model.provider}/${model.id}` : auth.error);
    }

    const content: Message["content"] = [
      { type: "text", text: query },
    ];

    // Add images if provided
    for (const url of imageUrls) {
      content.push({
        type: "image",
        source: url.startsWith("data:") ? url : { type: "url", url },
      } as any);
    }

    const userMessage: Message = {
      role: "user",
      content,
      timestamp: Date.now(),
    };

    const instructions = config.instructions || DEFAULT_CONFIG.instructions!;

    const response = await complete(
      model,
      { systemPrompt: instructions, messages: [userMessage] },
      { apiKey: auth.apiKey, headers: auth.headers, signal },
    );

    if (response.stopReason === "aborted") {
      return "[Vision model call aborted]";
    }

    return response.content
      .filter((c): c is { type: "text"; text: string } => c.type === "text")
      .map((c) => c.text)
      .join("\n");
  }

  // Update status indicator
  function updateStatus(ctx: ExtensionContext) {
    ctx.ui.setStatus("vision-router", ctx.ui.theme.fg("accent", `vision:${config.model}`));
  }

  // ============================================================
  // Register provider on session start
  // ============================================================

  pi.on("session_start", async (_event, ctx) => {
    config = loadConfig(ctx.cwd);
    registerVisionProvider();
    visionModel = null; // reset cache
    updateStatus(ctx);
  });

  // ============================================================
  // Register /vision command
  // ============================================================

  pi.registerCommand("vision", {
    description: "Route a query through the vision model. Usage: /vision <question>",
    handler: async (args, ctx) => {
      if (ctx.mode !== "tui") {
        ctx.ui.notify("/vision requires TUI mode", "error");
        return;
      }

      const query = args.trim();
      if (!query) {
        ctx.ui.notify("Usage: /vision <question>", "error");
        return;
      }

      // TODO: extract image URLs from recent conversation context
      const imageUrls: string[] = [];

      ctx.ui.notify(`Routing to vision model: ${config.provider}/${config.model}...`, "info");

      try {
        const result = await routeToVisionModel(query, imageUrls, ctx);

        // Show result via editor for review
        await ctx.ui.editor("Vision Model Response", result);
      } catch (err) {
        ctx.ui.notify(`Vision router error: ${err instanceof Error ? err.message : String(err)}`, "error");
      }
    },
  });

  // ============================================================
  // Register vision_query tool for LLM
  // ============================================================

  pi.registerTool({
    name: "vision_query",
    label: "Vision Query",
    description: "Route a question with optional images through the configured vision model. Use this for image analysis, visual understanding, or any task that benefits from a vision-capable model.",
    promptSnippet: "Use vision_query when the user asks about images, screenshots, diagrams, or any visual content. This routes to a dedicated vision model.",
    promptGuidelines: [
      "For image analysis tasks, use vision_query instead of analyzing images yourself if you're not a vision model.",
      "Pass the image URL or data URI in the imageUrls parameter.",
    ],
    parameters: Type.Object({
      query: Type.String({ description: "The question or task for the vision model" }),
      imageUrls: Type.Optional(
        Type.Array(Type.String(), { description: "URLs or data URIs of images to analyze" })
      ),
    }),

    async execute(_toolCallId, params, _signal, _onUpdate, ctx) {
      try {
        const result = await routeToVisionModel(
          params.query,
          params.imageUrls || [],
          ctx,
        );
        return {
          content: [{ type: "text", text: result }],
          details: { model: `${config.provider}/${config.model}`, query: params.query },
        };
      } catch (err) {
        return {
          content: [{ type: "text", text: `Vision query failed: ${err instanceof Error ? err.message : String(err)}` }],
          details: { error: true },
        };
      }
    },
  });

  // ============================================================
  // Register /vision-config command (Settings UI)
  // ============================================================

  pi.registerCommand("vision-config", {
    description: "Configure the vision router (provider, model, etc.)",
    handler: async (_args, ctx) => {
      if (ctx.mode !== "tui") {
        ctx.ui.notify("/vision-config requires TUI mode", "error");
        return;
      }

      await ctx.ui.custom((tui, theme, _kb, done) => {
        const items: SettingItem[] = [
          {
            id: "provider",
            label: "Provider",
            currentValue: config.provider,
            values: ["kimi", "openai", "anthropic", "openai-compatible"],
          },
          {
            id: "model",
            label: "Model ID",
            currentValue: config.model,
            values: [config.model], // free-text; user types custom value
          },
          {
            id: "baseUrl",
            label: "Base URL",
            currentValue: config.baseUrl || "",
            values: [config.baseUrl || ""],
          },
          {
            id: "api",
            label: "API Format",
            currentValue: config.api || "openai-responses",
            values: ["openai-responses", "openai-completions", "anthropic-messages"],
          },
          {
            id: "contextWindow",
            label: "Context Window",
            currentValue: String(config.contextWindow || 128000),
            values: ["32000", "64000", "128000", "200000"],
          },
          {
            id: "maxTokens",
            label: "Max Tokens",
            currentValue: String(config.maxTokens || 8192),
            values: ["4096", "8192", "16384"],
          },
        ];

        const container = new Container();
        container.addChild(
          new Text(theme.fg("accent", theme.bold("Vision Router Configuration"))),
        );
        container.addChild(new Text(""));

        const settingsList = new SettingsList(
          items,
          Math.min(items.length + 2, 15),
          getSettingsListTheme(),
          (id, newValue) => {
            switch (id) {
              case "provider": config.provider = newValue; break;
              case "model": config.model = newValue; break;
              case "baseUrl": config.baseUrl = newValue; break;
              case "api": config.api = newValue; break;
              case "contextWindow": config.contextWindow = parseInt(newValue, 10) || 128000; break;
              case "maxTokens": config.maxTokens = parseInt(newValue, 10) || 8192; break;
            }
          },
          () => {
            // Save and close
            saveConfig(config, ctx.cwd);
            registeredProvider = false; // will re-register on next use
            visionModel = null;
            updateStatus(ctx);
            ctx.ui.notify("Vision router config saved", "info");
            done(undefined);
          },
        );

        container.addChild(settingsList);

        return {
          render(width: number) {
            return container.render(width);
          },
          invalidate() {
            container.invalidate();
          },
          handleInput(data: string) {
            settingsList.handleInput?.(data);
            tui.requestRender();
          },
        };
      });
    },
  });
}
```

