  provider: string;
  model: string;
  label?: string;
  baseUrl?: string;
  api?: Api;
  apiKey?: string;
  instructions?: string;
  contextWindow?: number;
  maxTokens?: number;
  costInput?: number;
  costOutput?: number;
  costCacheRead?: number;
  costCacheWrite?: number;
}

const DEFAULT_CONFIG: VisionRouterConfig = {
  provider: "kimi",
  model: "kimi-k2.6-2",
  label: "Kimi K2.6 Vision",
  baseUrl: "http://localhost:19530/v1",
  api: "openai-responses",
  instructions:
    "You are a vision-specialist model. Analyze images and answer questions about them with detailed, accurate descriptions. Be thorough and specific.",
