export default function (pi: ExtensionAPI) {
  let config: VisionRouterConfig = { ...DEFAULT_CONFIG };
  let visionModel: Model<Api> | null = null;
  let registeredProvider = false;

  // Register the vision provider with the model registry
  function registerVisionProvider() {
    if (registeredProvider) return;

    try {
      pi.registerProvider(config.provider, {
        baseUrl: config.baseUrl ?? DEFAULT_CONFIG.baseUrl!,
        apiKey: config.apiKey || undefined,
        api: config.api ?? DEFAULT_CONFIG.api!,
        models: [
          {
            id: config.model,
            name: config.label ?? `${config.provider}/${config.model}`,
            reasoning: false,
            input: ["text", "image"],
            cost: {
              input: config.costInput ?? DEFAULT_CONFIG.costInput!,
              output: config.costOutput ?? DEFAULT_CONFIG.costOutput!,
              cacheRead: config.costCacheRead ?? DEFAULT_CONFIG.costCacheRead!,
              cacheWrite: config.costCacheWrite ?? DEFAULT_CONFIG.costCacheWrite!,
            },
            contextWindow: config.contextWindow ?? DEFAULT_CONFIG.contextWindow!,
            maxTokens: config.maxTokens ?? DEFAULT_CONFIG.maxTokens!,
          },
        ],
      });
      registeredProvider = true;
    } catch (err) {
      // Provider may already be registered (e.g. by another extension)
      registeredProvider = true;
    }
  }

  // Find the vision model in the registry
  function resolveVisionModel(ctx: ExtensionContext): Model<Api> | null {
    if (visionModel) return visionModel;

    const found = ctx.modelRegistry.find(config.provider, config.model);
    if (found) {
      visionModel = found;
      return found;
    }
    return null;
  }

  // Route a query through the vision model
  async function routeToVisionModel(
    query: string,
    images: Array<{ data: string; mimeType: string }>,
    ctx: ExtensionContext,
    signal?: AbortSignal,
  ): Promise<string> {
    registerVisionProvider();

    const model = resolveVisionModel(ctx);
    if (!model) {
      throw new Error(
        `Vision model ${config.provider}/${config.model} not found. ` +
          `Configure via /vision-config or edit vision-router.json.`,
      );
    }

    const auth = await ctx.modelRegistry.getApiKeyAndHeaders(model);
    if (!auth.ok || !auth.apiKey) {
      throw new Error(auth.ok ? `No API key for ${model.provider}/${model.id}` : auth.error);
    }

    const content: Message["content"] = [{ type: "text", text: query }];

    for (const img of images) {
      (content as any[]).push({
        type: "image",
        data: img.data,
        mimeType: img.mimeType,
      });
    }

    const userMessage: Message = {
      role: "user",
      content,
      timestamp: Date.now(),
    };

    const instructions =
      config.instructions ??
      "You are a vision-specialist model. Analyze images and answer questions about them.";

    const response = await complete(
      model,
      { systemPrompt: instructions, messages: [userMessage] },
      { apiKey: auth.apiKey, headers: auth.headers, signal },
    );

    if (response.stopReason === "aborted" || response.stopReason === "cancelled") {
      return "[Vision model call was aborted]";
    }

    return response.content
      .filter((c): c is { type: "text"; text: string } => c.type === "text")
      .map((c) => c.text)
      .join("\n");
