      images: Type.Optional(
        Type.Array(
          Type.Object({
            data: Type.String({ description: "Base64-encoded image data" }),
            mimeType: Type.String({ description: "MIME type: image/png, image/jpeg, etc." }),
          }),
          { description: "Images to analyze" },
        ),
